int main(void)
{
	DelayInit();

	// Initialize PWM
	PWM_Init();

	while (1)
	{
		// Set LED brightness from 0 to max
		for (brightness = 0; brightness <= 7199; brightness += 10)
		{
			TIM2->CCR1 = brightness;
			DelayMs(1);
		}
		// Set LED brightness from max to 0
		for (brightness = 7199; brightness >= 0; brightness -= 10)
		{
			TIM2->CCR1 = brightness;
			DelayMs(1);
		}
	}
}
